#include <stdio.h>

int main() {
    int n, i, factorial = 1;

    printf("Enter a non-negative integer: ");
    scanf("%d", &n);

    if (n < 0) {
        printf("Error: Factorial is not defined for negative numbers.\n");
        return 1; // Indicate an error
    }

    for (i = 1; i <= n; i++) {
        factorial = factorial * i;
    }

    printf("Factorial of %d = %d\n", n, factorial);

    return 0;
}
```

